#include "kernel_operator.h"

constexpr int32_t BUFFER_NUM = 2;

class KernelLayerNormCustom {
public:
    __aicore__ inline KernelLayerNormCustom() {}

    __aicore__ inline void Init(GM_ADDR x, GM_ADDR weight, GM_ADDR bias, GM_ADDR y,
                                uint32_t totalRows, uint32_t hiddenSize, float epsilon, float invHiddenSize) {
        totalRows_ = totalRows;
        hiddenSize_ = hiddenSize;
        epsilon_ = epsilon;
        invHiddenSize_ = invHiddenSize;

        xGm_.SetGlobalBuffer((__gm__ float*)x, totalRows * hiddenSize);
        wGm_.SetGlobalBuffer((__gm__ float*)weight, hiddenSize);
        bGm_.SetGlobalBuffer((__gm__ float*)bias, hiddenSize);
        yGm_.SetGlobalBuffer((__gm__ float*)y, totalRows * hiddenSize);

        pipe_.InitBuffer(inQueueX_, BUFFER_NUM, hiddenSize_ * sizeof(float));
        pipe_.InitBuffer(outQueueY_, BUFFER_NUM, hiddenSize_ * sizeof(float));
        pipe_.InitBuffer(tmpDiff_, 1, hiddenSize_ * sizeof(float));
        pipe_.InitBuffer(tmpSqr_, 1, hiddenSize_ * sizeof(float));
        pipe_.InitBuffer(scalar_, 1, sizeof(float));
        pipe_.InitBuffer(wsQueue_, 1, hiddenSize_ * sizeof(float));

        // Pre-allocate and load weight and bias once
        wLocal_ = tmpW_.AllocTensor<float>();
        bLocal_ = tmpB_.AllocTensor<float>();
        AscendC::DataCopy(wLocal_, wGm_, hiddenSize_);
        AscendC::DataCopy(bLocal_, bGm_, hiddenSize_);
    }

    __aicore__ inline void Process() {
        if (totalRows_ == 0 || hiddenSize_ == 0) return;

        uint32_t blockNum = AscendC::GetBlockNum();
        uint32_t blockIdx = AscendC::GetBlockIdx();
        uint32_t rowsPerBlock = (totalRows_ + blockNum - 1) / blockNum;
        uint32_t startRow = blockIdx * rowsPerBlock;
        uint32_t endRow = startRow + rowsPerBlock;
        if (endRow > totalRows_) endRow = totalRows_;

        for (uint32_t row = startRow; row < endRow; ++row) {
            uint32_t offset = row * hiddenSize_;

            // Load x row (double buffering)
            AscendC::LocalTensor<float> xLocal = inQueueX_.AllocTensor<float>();
            AscendC::DataCopy(xLocal, xGm_[offset], hiddenSize_);
            inQueueX_.EnQue(xLocal);

            Compute(row);
            CopyOut(row);
        }

        // Free weight and bias tensors
        tmpW_.FreeTensor(wLocal_);
        tmpB_.FreeTensor(bLocal_);
    }

private:
    __aicore__ inline void Compute(uint32_t row) {
        AscendC::LocalTensor<float> xLocal = inQueueX_.DeQue<float>();
        AscendC::LocalTensor<float> yLocal = outQueueY_.AllocTensor<float>();
        AscendC::LocalTensor<float> diffLocal = tmpDiff_.AllocTensor<float>();
        AscendC::LocalTensor<float> sqrLocal = tmpSqr_.AllocTensor<float>();
        AscendC::LocalTensor<float> scalarLocal = scalar_.AllocTensor<float>();
        AscendC::LocalTensor<float> wsLocal = wsQueue_.AllocTensor<float>();

        // Compute mean = sum(x) / N
        AscendC::ReduceSum(scalarLocal, xLocal, wsLocal, hiddenSize_);
        float mean_val = scalarLocal.GetValue(0) * invHiddenSize_;

        // Compute x - mean
        AscendC::Subs(diffLocal, xLocal, mean_val, hiddenSize_);

        // Compute variance = sum((x - mean)^2) / N
        AscendC::Mul(sqrLocal, diffLocal, diffLocal, hiddenSize_);
        AscendC::ReduceSum(scalarLocal, sqrLocal, wsLocal, hiddenSize_);
        float variance = scalarLocal.GetValue(0) * invHiddenSize_;

        // Standard deviation inverse
        float stdInv = 1.0f / sqrt(variance + epsilon_);

        // Normalize: y = (x - mean) * stdInv * weight + bias
        AscendC::Muls(diffLocal, diffLocal, stdInv, hiddenSize_);
        AscendC::Mul(yLocal, diffLocal, wLocal_, hiddenSize_);
        AscendC::Add(yLocal, yLocal, bLocal_, hiddenSize_);

        // Enqueue output for CopyOut
        outQueueY_.EnQue<float>(yLocal);

        // Free work tensors
        wsQueue_.FreeTensor(wsLocal);
        scalar_.FreeTensor(scalarLocal);
        tmpSqr_.FreeTensor(sqrLocal);
        tmpDiff_.FreeTensor(diffLocal);
        inQueueX_.FreeTensor(xLocal);
    }

    __aicore__ inline void CopyOut(uint32_t row) {
        AscendC::LocalTensor<float> yLocal = outQueueY_.DeQue<float>();
        uint32_t offset = row * hiddenSize_;
        AscendC::DataCopy(yGm_[offset], yLocal, hiddenSize_);
        outQueueY_.FreeTensor(yLocal);
    }

private:
    AscendC::TPipe pipe_;
    AscendC::TQue<AscendC::TPosition::VECIN, BUFFER_NUM> inQueueX_;
    AscendC::TQue<AscendC::TPosition::VECOUT, BUFFER_NUM> outQueueY_;
    AscendC::TQue<AscendC::TPosition::VECCALC, 1> tmpDiff_;
    AscendC::TQue<AscendC::TPosition::VECCALC, 1> tmpSqr_;
    AscendC::TQue<AscendC::TPosition::VECCALC, 1> scalar_;
    AscendC::TQue<AscendC::TPosition::VECCALC, 1> wsQueue_;

    AscendC::TBuf<AscendC::TPosition::VECCALC> tmpW_;
    AscendC::TBuf<AscendC::TPosition::VECCALC> tmpB_;
    AscendC::LocalTensor<float> wLocal_;
    AscendC::LocalTensor<float> bLocal_;

    AscendC::GlobalTensor<float> xGm_;
    AscendC::GlobalTensor<float> wGm_;
    AscendC::GlobalTensor<float> bGm_;
    AscendC::GlobalTensor<float> yGm_;

    uint32_t totalRows_;
    uint32_t hiddenSize_;
    float epsilon_;
    float invHiddenSize_;
};

